mapper.select:
SELECT A.APPLY_NO, A.PERSON_ID, A.LEAVE_TYPE_CODE AS ITEM_NO, GET_GLOBAL_NAME(A.LEAVE_TYPE_CODE, #{lang, jdbcType=VARCHAR}) AS LEAVE_TYPE_NAME, TO_CHAR(A.CREATE_DATE, 'DD/MM/YYYY') AS APPLY_DATE, TO_CHAR(A.LEAVE_FROM_TIME, 'DD/MM/YYYY') AS LEAVE_FROM_DATE, TO_CHAR(A.LEAVE_FROM_TIME, 'HH24:MI') AS LEAVE_FROM_TIME_ONLY, TO_CHAR(A.LEAVE_TO_TIME, 'DD/MM/YYYY') AS LEAVE_TO_DATE, TO_CHAR(A.LEAVE_TO_TIME, 'HH24:MI') AS LEAVE_TO_TIME_ONLY, A.APPLY_LENGTH, AR_GET_DAY_HOURS(A.PERSON_ID, A.LEAVE_FROM_TIME) AS DAY_HOURS, A.LEAVE_REASON, A.AFFIRM_FLAG, GET_GLOBAL_NAME(A.AFFIRM_FLAG, #{lang, jdbcType=VARCHAR}) AS AFFIRM_FLAG_NAME, A.HR_COMMENT, A.CONFIRM_FLAG, GET_GLOBAL_NAME(A.CONFIRM_FLAG, #{lang, jdbcType=VARCHAR}) AS CONFIRM_FLAG_NAME, GET_UPDATED_INFO(A.CREATED_BY) AS CREATED_BY, A.CREATED_IP, A.LEAVE_TYPE_CODE FROM ESS_LEAVE_APPLY_TB A WHERE A.PERSON_ID = #{adminID, jdbcType=VARCHAR} AND A.ACTIVITY = 1
AND A.LEAVE_TYPE_CODE = #{leaveTypeCode, jdbcType=VARCHAR}
AND A.AFFIRM_FLAG = #{affirmFlag, jdbcType=VARCHAR}
AND A.LEAVE_FROM_TIME >= TO_DATE(#{fromDate, jdbcType=VARCHAR}, 'YYYY-MM-DD')
AND A.LEAVE_FROM_TIME < TO_DATE(#{toDate, jdbcType=VARCHAR}, 'YYYY-MM-DD') + 1
ORDER BY A.CREATE_DATE DESC

